           <MessageBubble
             key={message.id}
             message={message}
             files={prFiles}
             onNavigate={handleCitationNavigate}
           />
         ))}
         <div ref={messagesEndRef} />
       </div>

       {/* Input */}
       <div className="flex-shrink-0 border-t border-border p-4">
         <div className="flex gap-2 items-end">
           <textarea
             ref={textareaRef}
             value={input}
             onChange={(e) => setInput(e.target.value)}
             onKeyDown={handleKeyDown}
             placeholder="Ask about this PR... (Enter to send, Shift+Enter for new line)"
             rows={1}
             disabled={isStreaming}
             className={cn(
               'flex-1 resize-none rounded-md border border-input bg-background px-3 py-2 text-sm',
               'placeholder:text-muted-foreground',
               'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1',
               'transition-colors disabled:opacity-50',
               'min-h-[40px] max-h-[120px]'
             )}
             style={{
               height: 'auto',
               overflowY: input.split('\n').length > 3 ? 'auto' : 'hidden',
             }}
             onInput={(e) => {
               const target = e.target as HTMLTextAreaElement;
               target.style.height = 'auto';
               target.style.height = `${Math.min(target.scrollHeight, 120)}px`;
             }}
           />
           <button
             onClick={() => void handleSend()}
             disabled={!input.trim() || isStreaming}
             className={cn(
               'flex-shrink-0 rounded-md p-2 h-10 w-10',
               'bg-primary text-primary-foreground',
               'hover:bg-primary/90',
               'transition-colors disabled:opacity-50 disabled:cursor-not-allowed',
               'flex items-center justify-center'
             )}
             title="Send message"
           >
             {isStreaming ? (
               <Loader2 className="h-4 w-4 animate-spin" />
             ) : (
               <Send className="h-4 w-4" />
             )}
           </button>
         </div>
         <p className="text-xs text-muted-foreground mt-1.5">
           {config.demoMode
             ? '🎭 Demo mode — using sample PR data'
             : `Using ${config.llmModel} via ${config.llmBackend}`}
         </p>
       </div>
     </div>
   );
 }

